function escapeHtml(text){const div=document.createElement('div');div.textContent=text||'';return div.innerHTML;}
function formatFileSize(bytes){if(bytes<1024)return bytes+' B';if(bytes<1024*1024)return(bytes/1024).toFixed(1)+' KB';return(bytes/(1024*1024)).toFixed(1)+' MB';}
function formatTime(isoString){if(!isoString)return'--';try{const d=new Date(isoString);const pad=(n)=>String(n).padStart(2,'0');return`${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;}catch(e){return'--';}}
function formatDate(isoString){if(!isoString)return'--';try{const d=new Date(isoString);const pad=(n)=>String(n).padStart(2,'0');return`${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}`;}catch(e){return'--';}}
function relativeTime(isoString){if(!isoString)return'--';try{const now=Date.now();const then=new Date(isoString).getTime();const diff=now-then;const sec=Math.floor(diff/1000);if(sec<60)return'刚刚';const min=Math.floor(sec/60);if(min<60)return`${min} 分钟前`;const hour=Math.floor(min/60);if(hour<24)return`${hour} 小时前`;const day=Math.floor(hour/24);return`${day} 天前`;}catch(e){return'--';}}
let _toastTimer=null;function showToast(message,type,duration){type=type||'info';duration=duration||4000;const container=document.getElementById('toast-container');if(!container)return;const icons={success:'✓',error:'✕',warning:'!',info:'i'};const toast=document.createElement('div');toast.className='toast toast-'+type;toast.setAttribute('role','alert');toast.setAttribute('aria-live','assertive');toast.innerHTML='<span aria-hidden="true" style="font-weight:700;font-size:0.85rem;">'+(icons[type]||'')+'</span><span>'+message+'</span>';container.appendChild(toast);if(_toastTimer)clearTimeout(_toastTimer);_toastTimer=setTimeout(function(){toast.style.animation='toast-out 0.3s ease forwards';setTimeout(function(){toast.remove();},300);},duration);}
function confirmDialog(message,title){return new Promise(function(resolve){if(typeof message==='object'&&message.preventDefault){return resolve(true);}
const result=window.confirm(message);resolve(result);});}
function debounce(fn,delay){let timer=null;return function(){const ctx=this;const args=arguments;clearTimeout(timer);timer=setTimeout(function(){fn.apply(ctx,args);},delay);};}
function throttle(fn,limit){let inThrottle=false;return function(){const ctx=this;const args=arguments;if(!inThrottle){fn.apply(ctx,args);inThrottle=true;setTimeout(function(){inThrottle=false;},limit);}};}
function initUploadZone(zoneId,inputSelector,nameDisplayId,iconId,textId){const zone=document.getElementById(zoneId);const input=zone?zone.querySelector(inputSelector):null;const nameDisplay=document.getElementById(nameDisplayId);const icon=iconId?document.getElementById(iconId):null;const text=textId?document.getElementById(textId):null;if(!zone||!input)return;input.addEventListener('change',function(){if(this.files&&this.files.length>0){const f=this.files[0];if(nameDisplay){nameDisplay.textContent=f.name+' ('+formatFileSize(f.size)+')';nameDisplay.style.display='block';}
if(icon)icon.textContent='\u2713';if(text)text.innerHTML='已选择文件';zone.classList.add('has-file');}});zone.addEventListener('dragover',function(e){e.preventDefault();zone.classList.add('dragover');});zone.addEventListener('dragleave',function(){zone.classList.remove('dragover');});zone.addEventListener('drop',function(){zone.classList.remove('dragover');});}
function initOptionCards(containerSelector){const container=document.querySelector(containerSelector);if(!container)return;const cards=container.querySelectorAll('.option-card-tile');cards.forEach(function(card){card.addEventListener('click',function(){const input=this.querySelector('input');if(!input)return;if(input.type==='radio'){const name=input.name;container.querySelectorAll('.option-card-tile input[name="'+name+'"]').forEach(function(other){other.closest('.option-card-tile').classList.remove('selected');});this.classList.add('selected');input.checked=true;}else if(input.type==='checkbox'){input.checked=!input.checked;this.classList.toggle('selected',input.checked);}});card.addEventListener('keydown',function(e){if(e.key==='Enter'||e.key===' '){e.preventDefault();this.click();}});});}
function stopPolling(elementId){const el=document.getElementById(elementId||'progress-area');if(el){el.removeAttribute('hx-trigger');el.removeAttribute('hx-get');if(typeof htmx!=='undefined')htmx.process(el);}}
(function(){const saved=localStorage.getItem('theme');const prefersDark=window.matchMedia('(prefers-color-scheme: dark)').matches;const theme=saved||(prefersDark?'dark':'light');document.documentElement.setAttribute('data-theme',theme);updateThemeColor(theme);const icon=document.getElementById('theme-icon');if(icon)icon.textContent=theme==='dark'?'☀️':'🌙';window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change',function(e){if(!localStorage.getItem('theme')){const t=e.matches?'dark':'light';document.documentElement.setAttribute('data-theme',t);updateThemeColor(t);if(icon)icon.textContent=e.matches?'☀️':'🌙';}});})();function updateThemeColor(theme){const meta=document.querySelector('meta[name="theme-color"]');if(meta){meta.content=theme==='dark'?'#111113':'#F8FAFC';}}
function toggleTheme(){const html=document.documentElement;const current=html.getAttribute('data-theme');const next=current==='dark'?'light':'dark';html.setAttribute('data-theme',next);localStorage.setItem('theme',next);updateThemeColor(next);const icon=document.getElementById('theme-icon');if(icon)icon.textContent=next==='dark'?'☀️':'🌙';}
document.addEventListener('DOMContentLoaded',function(){document.body.addEventListener('htmx:responseError',function(evt){showToast('请求失败: '+(evt.detail.xhr?evt.detail.xhr.status:'未知'),'error');});document.body.addEventListener('htmx:sendError',function(){showToast('网络错误，请检查连接','error');});document.body.addEventListener('htmx:beforeRequest',function(evt){const target=evt.detail.target;if(target)target.setAttribute('aria-busy','true');});document.body.addEventListener('htmx:afterRequest',function(evt){const target=evt.detail.target;if(target)target.removeAttribute('aria-busy');});});(function(){if('IntersectionObserver'in window){const observer=new IntersectionObserver(function(entries){entries.forEach(function(entry,i){if(entry.isIntersecting){setTimeout(function(){entry.target.style.opacity='1';entry.target.style.transform='translateY(0)';},i*60);observer.unobserve(entry.target);}});},{threshold:0.1,rootMargin:'0px 0px -20px 0px'});document.addEventListener('htmx:afterSwap',function(){document.querySelectorAll('.card, .pipeline-item, .kb-stat-card, .step-summary-card, .artifact-card, .search-result-item').forEach(function(el){if(!el.dataset.observed){el.dataset.observed='1';el.style.opacity='0';el.style.transform='translateY(12px)';el.style.transition='opacity 0.4s ease-out, transform 0.4s ease-out';observer.observe(el);}});});document.querySelectorAll('.card, .pipeline-item, .kb-stat-card, .step-summary-card, .artifact-card, .search-result-item').forEach(function(el){el.dataset.observed='1';el.style.opacity='0';el.style.transform='translateY(12px)';el.style.transition='opacity 0.4s ease-out, transform 0.4s ease-out';observer.observe(el);});}})();